import React from "react";
import { Outlet, Link, useLocation, useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  Package,
  ShoppingBag,
  ListTree,
  LogOut,
} from "lucide-react";

const AdminLayout = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: <LayoutDashboard size={18} /> },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: <Package size={18} /> },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: <ShoppingBag size={18} /> },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: <ListTree size={18} /> },
  ];

  const handleLogout = () => {
    localStorage.removeItem("token");
    navigate("/login");
  };

  return (
    <div className="flex min-h-screen bg-gray-50 text-gray-800">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r shadow-sm flex flex-col">
        <div className="px-5 py-6 border-b">
          <h2 className="text-xl font-bold text-green-700 tracking-tight">
            🌼 DTP Flower Shop
          </h2>
          <p className="text-sm text-gray-500 mt-1">Bảng quản trị</p>
        </div>

        <nav className="flex-1 px-3 py-4 space-y-1">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-3 px-4 py-2 rounded-lg text-sm font-medium transition-all duration-150 ${
                  isActive
                    ? "bg-green-100 text-green-700 shadow-sm"
                    : "text-gray-600 hover:bg-gray-100 hover:text-green-600"
                }`}
              >
                {item.icon}
                {item.name}
              </Link>
            );
          })}
        </nav>

        <div className="px-5 py-4 border-t mt-auto">
          <a
            href="/"
            target="_blank"
            rel="noreferrer"
            className="text-sm text-blue-600 hover:underline"
          >
            ↗ Xem trang web
          </a>
          <button
            onClick={handleLogout}
            className="flex items-center gap-2 text-red-500 hover:text-red-600 mt-3 text-sm font-medium"
          >
            <LogOut size={16} />
            Đăng xuất
          </button>
        </div>
      </aside>

      {/* Content area */}
      <main className="flex-1 flex flex-col bg-gray-50">
        {/* Header */}
        <header className="bg-white border-b shadow-sm px-6 py-4 flex justify-between items-center">
          <h1 className="text-lg font-semibold text-gray-700">
            Bảng điều khiển quản trị
          </h1>
          <div className="text-sm text-gray-600">
            Xin chào, <span className="font-medium text-green-700">Nguyễn Hồng Cẩm Tiên</span>
          </div>
        </header>

        {/* Main content */}
        <div className="flex-1 p-6">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
